#!/usr/bin/env node
import { chmod, writeFile } from "node:fs/promises";
import { existsSync } from "node:fs";
import { resolve } from "node:path";
import { createInterface } from "node:readline/promises";
import { stdin as input, stdout as output } from "node:process";
import { defaultEnvPath, loadEnvFile, projectRoot } from "./env.js";
async function main() {
    loadEnvFile();
    const rl = createInterface({ input, output });
    try {
        console.log("Power BI MCP setup");
        console.log(`Env file: ${defaultEnvPath()}`);
        console.log("");
        const modelingCommandDefault = process.env.POWERBI_MODELING_MCP_COMMAND || defaultModelingMcpCommand();
        const modelingCommand = await prompt(rl, "Microsoft Modeling MCP command", modelingCommandDefault);
        const modelingArgs = await prompt(rl, "Microsoft Modeling MCP args", process.env.POWERBI_MODELING_MCP_ARGS || defaultModelingMcpArgs(modelingCommand));
        const knownWorkspaces = await prompt(rl, "Known workspace names, comma-separated", process.env.POWERBI_KNOWN_WORKSPACES || process.env.POWERBI_DEFAULT_WORKSPACE || "");
        const defaultWorkspace = await prompt(rl, "Default CEO workspace", process.env.POWERBI_DEFAULT_WORKSPACE || firstCsvValue(knownWorkspaces));
        const defaultSemanticModel = await prompt(rl, "Default CEO semantic model, optional fallback", process.env.POWERBI_DEFAULT_SEMANTIC_MODEL || "");
        const reportOutputDir = await prompt(rl, "HTML report output folder, optional", process.env.POWERBI_REPORT_OUTPUT_DIR || process.env.POWERBI_DASHBOARD_OUTPUT_DIR || "");
        const lines = [
            "# Generated by npm run setup",
            `POWERBI_MODELING_MCP_COMMAND=${quote(modelingCommand)}`,
            `POWERBI_MODELING_MCP_ARGS=${quote(modelingArgs)}`,
            knownWorkspaces ? `POWERBI_KNOWN_WORKSPACES=${quote(knownWorkspaces)}` : undefined,
            defaultWorkspace ? `POWERBI_DEFAULT_WORKSPACE=${quote(defaultWorkspace)}` : undefined,
            defaultSemanticModel ? `POWERBI_DEFAULT_SEMANTIC_MODEL=${quote(defaultSemanticModel)}` : undefined,
            reportOutputDir ? `POWERBI_REPORT_OUTPUT_DIR=${quote(reportOutputDir)}` : undefined,
            ""
        ].filter((line) => line !== undefined);
        await writeFile(defaultEnvPath(), lines.join("\n"), { mode: 0o600 });
        await chmod(defaultEnvPath(), 0o600);
        console.log("");
        console.log("Saved .env. Run `npm run build` then `npm start` or point Claude to dist/server.js.");
    }
    finally {
        rl.close();
    }
}
function prompt(rl, label, defaultValue) {
    const suffix = defaultValue ? ` [${defaultValue}]` : "";
    return new Promise(resolve => {
        rl.question(`${label}${suffix}: `).then(answer => {
            resolve(answer.trim() || defaultValue);
        });
    });
}
function quote(value) {
    return JSON.stringify(value);
}
function firstCsvValue(value) {
    return value.split(",").map(item => item.trim()).find(Boolean) || "";
}
function defaultModelingMcpCommand() {
    const nativeBinary = nativeModelingMcpBinaryPath();
    if (nativeBinary && existsSync(nativeBinary))
        return nativeBinary;
    return "npx";
}
function defaultModelingMcpArgs(command) {
    if (command === "npx") {
        return "-y @microsoft/powerbi-modeling-mcp@latest --start --authmode=interactive";
    }
    return "--start --authmode=interactive";
}
function nativeModelingMcpBinaryPath() {
    const platform = process.platform;
    const arch = process.arch;
    if (platform === "darwin" && arch === "arm64") {
        return resolve(projectRoot(), "node_modules/@microsoft/powerbi-modeling-mcp-darwin-arm64/dist/powerbi-modeling-mcp");
    }
    if (platform === "darwin" && arch === "x64") {
        return resolve(projectRoot(), "node_modules/@microsoft/powerbi-modeling-mcp-darwin-x64/dist/powerbi-modeling-mcp");
    }
    if (platform === "win32") {
        return resolve(projectRoot(), "node_modules/@microsoft/powerbi-modeling-mcp-win32-x64/dist/powerbi-modeling-mcp.exe");
    }
    return undefined;
}
main().catch(error => {
    console.error(error instanceof Error ? error.message : error);
    process.exit(1);
});
